The console shows this warning. Look at the code -- what needs to change?

```
Warning: Each child in a list should have a unique "key" prop.
```

```typescript
function TagList({ tags }: { tags: string[] }) {
  return (
    <div className="tags">
      {tags.map((tag, index) => (
        <span key={index} className="tag">
          {tag}
        </span>
      ))}
    </div>
  );
}
